$headers = @{
    "Authorization" = "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..ASBNqT9MeaJc1HgOUxQScSgNUYDfVMRpt2wFIQ7keOM"
}

$response = Invoke-RestMethod -Uri "http://localhost:5191/api/Trips/36" -Headers $headers -Method Get

Write-Host "`n=== TRIP DETAILS ===" -ForegroundColor Cyan
Write-Host "Trip ID: $($response.data.id)" -ForegroundColor Yellow
Write-Host "Trip Reference: $($response.data.tripReference)" -ForegroundColor Yellow
Write-Host "`n=== TRIP STOPS ===" -ForegroundColor Cyan

if ($response.data.tripStops) {
    Write-Host "Number of TripStops: $($response.data.tripStops.Count)" -ForegroundColor Green
    foreach ($stop in $response.data.tripStops) {
        Write-Host "`nStop $($stop.sequence):" -ForegroundColor White
        Write-Host "  Address: $($stop.address)" -ForegroundColor Gray
        Write-Host "  Latitude: $($stop.latitude)" -ForegroundColor Gray
        Write-Host "  Longitude: $($stop.longitude)" -ForegroundColor Gray
        Write-Host "  Customer: $($stop.customerName)" -ForegroundColor Gray
        Write-Host "  Order: $($stop.orderReference)" -ForegroundColor Gray
    }
} else {
    Write-Host "❌ NO TRIPSTOPS FOUND IN API RESPONSE!" -ForegroundColor Red
    Write-Host "`nAvailable properties in response.data:" -ForegroundColor Yellow
    $response.data.PSObject.Properties | ForEach-Object {
        Write-Host "  - $($_.Name)" -ForegroundColor Gray
    }
}